INSERT INTO `movies` VALUES (1,'Avengers: Endgame','Biệt đội Avengers tập hợp lần cuối để đảo ngược hậu quả từ cú búng tay của Thanos.',181,'2025-11-13','Anthony Russo, Joe Russo','','Action, Adventure, Sci-Fi','English','https://th.bing.com/th/id/OIP.AsVeA2uTH8DIHIezO_yDGAHaK-?w=119&h=180&c=7&r=0&o=7&dpr=2&pid=1.7&rm=3','https://www.youtube.com/embed/TcMBFSGVi1c','T13','now_showing','2026-03-09 00:57:25','2026-05-21 01:16:51',0),(2,'Spider-Man: No Way Home','Peter Parker phải đối mặt với hậu quả khi danh tính bị lộ và đa vũ trụ bị phá vỡ.',148,'2026-01-09','Jon Watts','Tom Holland, Zendaya, Benedict Cumberbatch','Action, Adventure, Fantasy','English','https://th.bing.com/th/id/OIP.jFWga73Vye9w2gQvqWJX6gHaLH?w=115&h=180&c=7&r=0&o=7&dpr=2&pid=1.7&rm=3','https://www.youtube.com/watch?v=JfVOs4VSpmA&t=18s','P','now_showing','2026-03-09 00:57:25','2026-03-08 18:03:04',0),(3,'Doraemon: Nobita and the Sky Utopia','Nobita và Doraemon phiêu lưu đến vương quốc trên bầu trời.',107,'2025-12-09','Takumi Doyama','Wasabi Mizuta, Megumi Ohara','Animation, Family, Fantasy','Japanese','https://th.bing.com/th/id/OIP.gvr7hO-OSR7Zbwf9-_w9RwHaHa?w=179&h=180&c=7&r=0&o=7&dpr=2&pid=1.7&rm=3','https://www.youtube.com/watch?v=Ol6Z_QR-OH8','P','now_showing','2026-03-09 00:57:25','2026-03-08 18:03:16',0),(4,'Godzilla x Kong: The New Empire','Godzilla và Kong đối đầu với mối đe dọa mới có thể hủy diệt thế giới.',115,'2026-02-12','Adam Wingard','Rebecca Hall, Brian Tyree Henry','Action, Sci-Fi','English','https://th.bing.com/th/id/OIP.OCOslhU1srFM_5vAPeUD5wHaLH?w=115&h=180&c=7&r=0&o=7&dpr=2&pid=1.7&rm=3','https://youtuhttps://www.youtube.com/watch?v=lV1OOlGwExM&t=17sbe.com/watch?v=example2','P','now_showing','2026-03-09 00:57:25','2026-03-08 18:03:25',0),(5,'Inside Out 2','Những cảm xúc mới xuất hiện trong tâm trí của Riley khi cô bước vào tuổi teen.',96,'2026-02-12','Kelsey Mann','Amy Poehler, Phyllis Smith','Animation, Comedy, Family','English','https://th.bing.com/th/id/OIP.s01urkcK6XmX5n-wjk3xpgHaK-?w=115&h=180&c=7&r=0&o=7&dpr=2&pid=1.7&rm=3','https://www.youtube.com/watch?v=VWavstJydZU','P','now_showing','2026-03-09 00:57:25','2026-03-08 18:03:36',0),(6,'THỎ ƠI!!','Phim “Thỏ ơi!!” dự kiến công chiếu trong dịp Tết 2026, thuộc thể loại hài, tâm lý sở trường của Trấn Thành, mang màu sắc trẻ trung với dàn diễn viên mới, tiếp nối tinh thần đem đến cho khán giả những điều vui vẻ, hài hước vào dịp Tết Nguyên đán.',127,'2026-02-17','Trấn Thành','Pháo; Lyly; Trấn Thành; Pháp Kiều; Gil Lê; Cris Phan; Ali Hoàng Dương; BB Trần; Đinh Ngọc Diệp','Tâm Lý','Tiếng Việt - Phụ đề Tiếng Anh','https://iguov8nhvyobj.vcdn.cloud/media/catalog/product/cache/1/image/c5f0a1eff4c394a251036189ccddaacd/t/o/to_poster_official_tiectet_3x4_fa.jpg','https://www.youtube.com/watch?v=aJOXdRSj91g','P','now_showing','2026-03-08 18:07:35',NULL,0),(7,'CẢM ƠN NGƯỜI ĐÃ THỨC CÙNG TÔI','Cảm Ơn Người Đã Thức Cùng Tôi là một hành trình cảm xúc của những người trẻ đi tìm đáp án cho câu hỏi “Ước mơ của bạn là gì?”, để rồi chính họ khi bước vào thế giới trưởng thành dần nhận ra câu hỏi quan trọng nhất là “Mình muốn thực hiện ước mơ đó cùng ai?”',137,'2026-02-27','Chung Chí Công','Võ Phan Kim Khánh, Trần Doãn Hoàng, Nguyễn Hùng','Gia đình, Tình cảm','Tiếng Việt','https://iguov8nhvyobj.vcdn.cloud/media/catalog/product/cache/1/image/c5f0a1eff4c394a251036189ccddaacd/m/a/main_condtct_cinema_low.jpg','https://www.youtube.com/watch?v=uf2oOeJ-Z3s&list=RDuf2oOeJ-Z3s&start_radio=1','P','now_showing','2026-03-08 18:08:43',NULL,0),(8,'BÁU VẬT TRỜI CHO','BÁU VẬT TRỜI CHO - bộ phim đa sắc cảm xúc, rực rỡ yêu thương, gắn kết gia đình Tết 2026. Ngọc (Phương Anh Đào) là mẹ đơn thân, có con nhờ thụ tinh nhân tạo từ tinh trùng hiến tặng. Trong chuyến đi biển để đổi gió và trốn chạy quá khứ, cô & Tô chạm mặt Hồng (Tuấn Trần) – chàng trai làng chài phóng khoáng, cũng chính là người góp phần tạo nên sự ra đời của Tô. Cuộc gặp gỡ tréo ngoe ấy kéo ba con người xa lạ vào hàng loạt tình huống dở khóc dở cười lẫn căng thẳng, khi mọi thứ bắt đầu vượt ngoài kế hoạch. Liệu người cha “trời cho” này là món quà bất ngờ của số phận, hay chỉ là một “trò chơi” oái oăm cuộc đời?',124,'2026-02-17','Lê Thanh Sơn','NSND Kim Xuân, Tuấn Trần, Phương Anh Đào, Võ Tấn Phát, Hưng Nguyễn, La Thành, Trung Dân, Khương Lê, Tạ Lâm, Quách Ngọc Ngoan, Chị Phiến, Thư Đan…','Gia đình, Hài, Tình cảm','Tiếng Việt - Phụ đề tiếng Anh','https://iguov8nhvyobj.vcdn.cloud/media/catalog/product/cache/1/image/c5f0a1eff4c394a251036189ccddaacd/4/7/470wx700h-bvtc_3.jpg','https://www.youtube.com/watch?v=dwfUi9SV5ss','P','now_showing','2026-03-08 18:10:04',NULL,0),(9,'KHÔNG CÒN CHÚNG TA','Jeong-won và Eun-ho yêu nhau chân thành và sâu đậm bằng những tất cả những gì họ có ở khoảng thời gian đẹp nhất của thanh xuân. Nhưng tình yêu của tuổi trẻ không tránh khỏi sự non nớt, bồng bột để rồi họ chọn rời xa nhau. Nhiều năm sau gặp lại, họ nhận ra: chính những tháng năm đã yêu và đã đau ấy đã giúp họ trưởng thành hơn, hiểu được tình yêu và biết cách yêu thương hơn. Chỉ tiếc rằng khi ấy, yêu thương này họ không dành cho nhau được nữa…',114,'2026-03-06','Kim Do-Young','Koo Kyo-hwan, Moon Ga-young, Suyeon Ji','Tâm Lý, Tình cảm','Tiếng Hàn – Phụ đề tiếng Việt','https://iguov8nhvyobj.vcdn.cloud/media/catalog/product/cache/1/image/c5f0a1eff4c394a251036189ccddaacd/4/7/470x700-us.jpg','https://www.youtube.com/watch?v=DltytoKP7Rg','P','now_showing','2026-03-08 18:11:24',NULL,0),(10,'MÙI PHỞ','Câu chuyện về sự xung đột thế hệ và những va chạm giữa quan niệm cũ và lối sống hiện đại, xoay quanh món Phở - biểu tượng ẩm thực Việt. Đằng sau những mâu thuẫn và tranh cãi ấy, từng bí mật dần được hé lộ, mở ra hành trình tìm lại sự ấm áp của tình thân qua những tình tiết hài hước, dí dỏm và đầy duyên dáng.',111,'2026-02-17','Minh Beta','Xuan Hinh - Thu Trang - Thanh Thanh Hien - Quoc Tuan - Bao Nam - Ha Huong - Thanh Huong - Chu Manh Cuong - Tien Loc','Gia đình, Hài','Tiếng Việt','https://iguov8nhvyobj.vcdn.cloud/media/catalog/product/cache/1/image/c5f0a1eff4c394a251036189ccddaacd/3/5/350x495-muipho.jpg','https://www.youtube.com/watch?v=7L5qkIkkcY8','P','now_showing','2026-03-08 18:12:54',NULL,0),(11,'TỘI PHẠM 101','Lấy bối cảnh thành phố Los Angeles đầy nắng và bụi đường, Tội Phạm 101 kể về một tên trộm nữ trang bí ẩn (Chris Hemsworth) với hàng loạt phi vụ táo bạo khiến cảnh sát phải đau đầu. Trong lúc chuẩn bị cho phi vụ lớn nhất của mình, hắn gặp gỡ một nữ nhân viên bảo hiểm (Halle Berry), người cũng đang vật lộn với những lựa chọn trong đời mình. Trong khi đó, một thanh tra (Mark Ruffalo) đã tìm ra quy luật trong chuỗi các vụ án và đang ráo riết truy đuổi tên trộm, khiến cuộc chơi trở nên căng thẳng hơn bao giờ hết. Khi phi vụ định mệnh đến gần, ranh giới giữa kẻ săn đuổi và con mồi dần trở nên mờ nhạt và cả ba buộc phải đối mặt với những lựa chọn khó khăn và không còn cơ hội để quay đầu lại. Bộ phim được chuyển thể từ tiểu thuyết ngắn nổi tiếng cùng tên của Don Winslow, do Bart Layton (tác giả của American Animals, The Imposter) viết kịch bản và đạo diễn. Dàn diễn viên có sự tham gia của Barry Keoghan, Monica Barbaro, Corey Hawkins, Jennifer Jason Leigh và Nick Nolte.',129,'2026-03-13','Bart Layton','Chris Hemsworth, Mark Ruffalo, Halle Berry, Barry Keoghan, Monica Barbaro, Corey Hawkins, Jennifer Jason Leigh, Nick Nolte','Hồi hộp, Tội phạm','Tiếng Anh - Phụ đề Tiếng Việt','https://iguov8nhvyobj.vcdn.cloud/media/catalog/product/cache/1/image/c5f0a1eff4c394a251036189ccddaacd/p/o/poster-crime.jpg','https://www.youtube.com/watch?v=TxY9GfEEMOI&t=2s','P','now_showing','2026-03-08 18:14:09','2026-06-11 22:30:43',0),(12,'CÔ DÂU!','Một cách tiếp cận táo bạo, phá vỡ mọi khuôn mẫu đối với một trong những câu chuyện hấp dẫn nhất thế giới. Bộ phim theo chân Frankenstein cô đơn (do Chrisitian Bale thủ vai) lên đường đến Chicago những năm 1930 để tìm đến nhà khoa học Dr. Euphronious (Annette Bening – 5 lần đề cử Oscar thủ vai), với hy vọng bà có thể tạo ra một người bạn đồng hành cho mình. Cả hai hồi sinh một cô gái trẻ đã bị sát hại, và Cô Dâu (Buckley thủ vai) đã ra đời. Những gì xảy ra sau đó đã vượt xa mọi tưởng tượng của họ: những vụ giết người, sự chiếm hữu, một phong trào văn hóa hoang dại và cấp tiến cũng như mối tình ngoài vòng pháp luật đầy cuồng nhiệt và bùng nổ!',126,'2026-03-13','Maggie Gyllenhaal','Jake Gyllenhaal, Christian Bale, Jessie Buckley,…','Kinh Dị, Nhạc kịch, Tình cảm','Tiếng Anh – phụ đề tiếng Việt','https://iguov8nhvyobj.vcdn.cloud/media/catalog/product/cache/1/image/c5f0a1eff4c394a251036189ccddaacd/m/a/main_poster_co_dau_1_final.jpg','https://www.youtube.com/watch?v=HYIOdcSGON4','P','now_showing','2026-03-08 18:15:36','2026-06-11 22:33:48',0),(13,'TIẾNG THÉT 7','Sidney Evans (Neve Campbell), nạn nhân sống sót của một vụ thảm sát nhiều năm trước, giờ đang sống hạnh phúc cùng chồng và con gái ở một thị trấn khác thì tên sát nhân Ghostface mới lại xuất hiện. Những nỗi sợ hãi đen tối nhất của cô trở thành hiện thực khi con gái cô Tatum Evans (Isabel May) trở thành mục tiêu tiếp theo. Quyết tâm bảo vệ gia đình, Sidney buộc phải đối mặt với những kinh hoàng trong quá khứ để chấm dứt cuộc đổ máu một lần và mãi mãi.',144,'2026-03-20','Kevin Williamson','Neve Campbell, Isabel May, Mckenna Grace, Courteney Cox, etc.','Bí ẩn, Kinh Dị','Tiếng Anh - Phụ đề Tiếng Việt','https://iguov8nhvyobj.vcdn.cloud/media/catalog/product/cache/1/image/c5f0a1eff4c394a251036189ccddaacd/s/c/sc7_burnposter_470x700.jpg','https://www.youtube.com/watch?v=4g8OciWNJn4','P','now_showing','2026-03-08 18:18:35','2026-06-11 22:37:39',0),(14,'THOÁT KHỎI TẬN THẾ','Ryland Grace một giáo viên khoa học nhận ra anh chính là hy vọng cuối cùng của Trái Đất. Nhiệm vụ của anh: cứu lấy Mặt Trời khỏi một sinh thể bí ẩn đang hút cạn năng lượng ánh sáng, đẩy cả hệ Mặt Trời vào bóng tối vĩnh viễn. Nếu thất bại, sự sống trên Trái Đất sẽ lụi tàn theo ánh sáng cuối cùng của mặt trời. Giữa không gian vũ trụ cô độc và áp lực của thời gian đang cạn dần, mọi phép tính, mọi quyết định của anh đều gánh trên vai số phận của toàn nhân loại. Nhưng trong hành trình tưởng chừng chỉ có một mình giữa khoảng không vô tận ấy, một tình bạn bất ngờ với một sinh vật ngoài hành tinh đã xuất hiện. Và có lẽ, để cứu Trái Đất, anh sẽ không phải chiến đấu một mình.',111,'2026-03-20','Phil Lord, Christopher Miller','Ryan Gosling, Liz Kingsman, Milana Vayntrub, Sandra Hüller','Khoa Học Viễn Tưởng, Phiêu Lưu','Tiếng Anh - Phụ đề Tiếng Việt','https://iguov8nhvyobj.vcdn.cloud/media/catalog/product/cache/1/image/c5f0a1eff4c394a251036189ccddaacd/3/5/350x495-mary.jpg','https://www.youtube.com/embed/ZhyHDNbxfcY','P','now_showing','2026-03-08 18:19:49','2026-06-11 22:37:40',0),(15,'CHÚNG SẼ ĐOẠT MẠNG','Đến từ New Line Cinema và Nocturna, CHÚNG SẼ ĐOẠT MẠNG (tựa gốc: THEY WILL KILL YOU) là một tác phẩm kinh dị - hành động - hài hước đẫm máu và đầy kịch tính xoay quanh cuộc chiến sống còn của một người phụ nữ tại tòa nhà xa hoa The Virgil - hang ổ của một giáo phái ma quỷ. Khi màn đêm buông xuống, những cạm bẫy được giăng ra, kẻ không thể sống sót sẽ trở thành vật tế tiếp theo. Một trận chiến chết chóc mãn nhãn cùng phong cách hài đen đầy mê hoặc sẽ sớm bắt đầu trên màn ảnh rộng.',136,'2026-03-27','Kirill Sokolov','Zazie Beetz, Myha’La, Paterson Joseph, Tom Felton, Heather Graham, Patricia Arquette,...','Hài, Hành Động, Kinh Dị','Tiếng Anh – Phụ đề Tiếng Việt','https://iguov8nhvyobj.vcdn.cloud/media/catalog/product/cache/1/image/c5f0a1eff4c394a251036189ccddaacd/v/n/vn_twky_vert_main_2764x4096_intl.jpg','https://www.youtube.com/watch?v=N-_NK612uH8','P','now_showing','2026-03-08 18:21:24','2026-06-11 22:37:40',0),(16,'PHIM SHIN - CẬU BÉ BÚT CHÌ: QUẬY TUNG! VƯƠNG QUỐC NGUỆCH NGOẠC VÀ 4 DŨNG SĨ BẤT ỔN','Bộ phim xoay quanh một vương quốc lơ lửng mang tên Rakuga, tồn tại nhờ nguồn năng lượng đến từ những nét vẽ của con người. Nhưng khi thế giới loài người dần đánh mất sự sáng tạo, Rakuga đứng bên bờ sụp đổ. Giữa thời khắc hỗn loạn, Shin vô tình nắm giữ cây bút chì màu kỳ diệu – có thể biến mọi hình vẽ thành hiện thực. Từ những nét vẽ ngây ngô nhất, bốn “vị anh hùng bất ổn” ra đời, đồng hành cùng cậu trong chuyến phiêu lưu vừa hài hước vừa kịch tính. Khi ranh giới giữa tưởng tượng và thực tại bị xóa nhòa, Shin không chỉ chiến đấu để cứu một vương quốc, mà còn để bảo vệ điều quý giá nhất: khả năng mơ mộng và sáng tạo của trẻ em.',104,'2026-05-03','Masakazu Hashimoto',' Akiko Yajima Shin Yumiko Kobayashi, Miki Narahashi,Toshiyuki Morikawa','Hài, Hoạt hình, Gia đình','Tiếng Nhật - Phụ Đề Tiếng Việt','https://upload.wikimedia.org/wikipedia/en/8/8e/Rakuga_kingdom_poster.jpg','https://www.youtube.com/watch?v=-dTuXbxiNcc','P',NULL,'2026-05-13 15:24:07','2026-05-21 00:00:20',0),(17,'MORTAL KOMBAT: CUỘC CHIẾN SINH TỬ II (T18)','Hãng phim New Line Cinema, phần tiếp theo đầy kịch tính trong loạt phim bom tấn chuyển thể từ trò chơi điện tử đình đám – Mortal Kombat II – trở lại với tất cả sự tàn bạo vốn có. Lần này, những nhà vô địch được yêu thích – nay có sự góp mặt của chính Johnny Cage – sẽ đối đầu với nhau trong trận chiến đẫm máu, không khoan nhượng, nhằm đánh bại thế lực đen tối của Shao Kahn đang đe dọa đến sự tồn vong của Earthrealm và các chiến binh bảo vệ nó.',116,'2026-05-13',' Simon McQuoid',' Karl Urban, Adeline Rudolph, Jessica McNamee, Josh Lawson, Ludi Lin, Mehcad Brooks, Tati Gabrielle, Lewis Tan,..','Hành Động, Phiêu Lưu, Thần thoại',' Tiếng Anh - Phụ Đề Tiếng Việt','https://starlight.vn/Areas/Admin/Content/Fileuploads/images/POSTER2026/motal%20kombat.jpg','https://www.youtube.com/watch?v=_UYoxtVTKEI','P',NULL,'2026-05-13 15:39:07','2026-05-13 15:39:07',0),(18,'ĐỘI THÁM TỬ CỪU','Đội Thám Tử Cừu: Án Mạng Lúc Nửa Đêm, phim trinh thám mới nhất quy tụ dàn sao Hollywood bom tấn để cùng giải mã bí ẩn cái chết của một thợ chăn cừu. Khi George đột ngột bị sát hại tại trang trại, cảnh sát địa phương tỏ ra bất lực trong việc tìm hung thủ. Đàn cừu quyết định tự mình thực hiện cuộc điều tra, sử dụng những kiến thức đã học được để lật tẩy kẻ thủ ác và bảo vệ trang trại.',109,'2026-05-13',' Kyle Balda',' Hugh Jackman, Emma Thompson, Nicholas Braun, Nicholas Galitzine, Molly Gordon. Hong Chau, Tosin Cole, Kobna Holdbrook-Smith, Conleth Hill, Mandeep Dhillon, Bryan Cranston, Julia Louis-Dreyfus, Patrick Stewart','Hài, Hành động, Bí ẩn',' Tiếng Anh - Phụ Đề Tiếng Việt','https://dcine.vn/Areas/Admin/Content/Fileuploads/images/doithamtucuuPoster.jpg','https://www.youtube.com/watch?v=7wU_SB2HTaY','P',NULL,'2026-05-13 15:44:50','2026-05-13 15:44:50',0),(19,'MÈO SIÊU QUẬY Ở VIỆN BẢO TÀNG 2: ĐẠI NÁO KIM TỰ THÁP','Hai năm đã trôi qua kể từ khi bảo tàng Hermitage được giải cứu thành công, còn bức tranh Mona Lisa bị đánh cắp. Chú chuột Maurice vẫn luôn mơ mộng về những cuộc phiêu lưu mới, trong khi cặp đôi Vincent và Cleopatra đã có thêm hai chú mèo con hiếu động và cũng đang khao khát những chuyến hành trình đầy thú vị',90,'2026-05-13',' Vasiliy Rovenskiy',' Roman Kurtsyn, Snezhana Samokhina, Diomid Vinogradov,...','Hài, Hành động, Hoạt hình',' Tiếng Anh - Phụ Đề Tiếng Việt','https://iguov8nhvyobj.vcdn.cloud/media/catalog/product/cache/1/image/1800x/71252117777b696995f01934522c402d/p/o/poster_payoff_cats_in_the_museum.jpg','https://www.youtube.com/watch?v=gG5QWGk5ZF4','P',NULL,'2026-05-13 15:51:42','2026-05-13 15:51:42',0),(20,'THẨM MỸ VIỆN ÂM PHỦ','Bộ phim xoay quanh Thanh (Ngọc Trinh), một nữ bác sĩ trẻ dấn thân vào thẩm mỹ viện biệt lập và kỳ quái để tìm cách cứu người yêu đang hôn mê. Tại đây, cô được bà Xuân (Xuân Lan) - chủ cơ sở, dẫn dắt vào những ca phẫu thuật thay đổi diện mạo đầy bí ẩn và nhuốm màu tà thuật. Thanh dần phát hiện mình là vật hiến tế trong một nghi thức mang tên “đi thiếp”. Những hiện tượng siêu nhiên và cơn ác mộng liên tục xuất hiện, xóa nhòa ranh giới giữa sự sống và cái chết. Cô buộc phải đối mặt với thế lực hắc ám để giành lại quyền kiểm soát số phận của chính mình.',97,'2026-05-13','  Nguyễn Hữu Hoàng','','Kinh dị','Tiếng Việt','https://iguov8nhvyobj.vcdn.cloud/media/catalog/product/cache/1/image/c5f0a1eff4c394a251036189ccddaacd/4/7/470wx700h-tmv.jpg','https://www.youtube.com/embed/puIIHiE8OOE','T18','now_showing','2026-05-13 16:03:22','2026-05-21 01:17:03',0),(21,'LÚC ĐÓ TÔI ĐÃ CHUYỂN SINH THÀNH SLIME: NƯỚC MẮT ĐẠI DƯƠNG','Lúc đó tôi đã chuyển sinh thành Slime: Nước Mắt Đại Dương là phần phim điện ảnh thứ 2 thuộc franchise anime nổi tiếng Lúc đó tôi đã chuyển sinh thành Slime. Lấy bối cảnh sau Lễ hội Khai quốc Tempest, Rimuru cùng những người bạn đồng hành quyết định ghé thăm một khu nghỉ dưỡng sang trọng do Elmesia, người đứng đầu Đế chế Pháp Thuật Sarion, cai quản, để tận hưởng thời gian thư giãn hiếm hoi sau những biến cố. Tuy nhiên, chuyến nghỉ dưỡng nhanh chóng bị xáo trộn khi nhân vật bí ẩn tên Yura xuất hiện, kéo theo một chuỗi những sự kiện bí ẩn và mối nguy đang âm thầm trỗi dậy dưới đại dương.',105,'2026-05-20','Yasuhito Kikuchi','Miho Okasaki, Mao Ichimichi, Tomoaki Maeno, Makoto Furukawa, Sayaka Senbongi','Hoạt Hình','Tiếng Nhật - Phụ đề Tiếng Việt','https://media.lottecinemavn.com/Media/MovieFile/MovieImg/202604/12179_203_100001.jpg','https://www.youtube.com/watch?v=Ixu8jbrhqnU','P',NULL,'2026-05-20 12:21:11','2026-05-20 12:21:11',0),(22,'LÚC ĐÓ TÔI ĐÃ CHUYỂN SINH THÀNH SLIME: NƯỚC MẮT ĐẠI DƯƠNG','Lúc đó tôi đã chuyển sinh thành Slime: Nước Mắt Đại Dương là phần phim điện ảnh thứ 2 thuộc franchise anime nổi tiếng Lúc đó tôi đã chuyển sinh thành Slime. Lấy bối cảnh sau Lễ hội Khai quốc Tempest, Rimuru cùng những người bạn đồng hành quyết định ghé thăm một khu nghỉ dưỡng sang trọng do Elmesia, người đứng đầu Đế chế Pháp Thuật Sarion, cai quản, để tận hưởng thời gian thư giãn hiếm hoi sau những biến cố. Tuy nhiên, chuyến nghỉ dưỡng nhanh chóng bị xáo trộn khi nhân vật bí ẩn tên Yura xuất hiện, kéo theo một chuỗi những sự kiện bí ẩn và mối nguy đang âm thầm trỗi dậy dưới đại dương.',105,'2026-05-20','Yasuhito Kikuchi','Miho Okasaki, Mao Ichimichi, Tomoaki Maeno, Makoto Furukawa, Sayaka Senbongi','Hoạt Hình','Tiếng Nhật - Phụ đề Tiếng Việt','https://media.lottecinemavn.com/Media/MovieFile/MovieImg/202604/12179_203_100001.jpg','https://www.youtube.com/watch?v=Ixu8jbrhqnU','P',NULL,'2026-05-20 14:54:21','2026-05-20 14:55:17',1),(23,'test them phim','anc',222,'2026-05-21','teest','abc','Gia đình','Tiếng Anh','','','T13','now_showing','2026-05-21 21:32:14','2026-06-11 22:37:40',1),(24,'123','442tvgsdrwjkrh',11,'2026-05-23','124','2222e','Phiêu lưu','Tiếng Anh','ee','e','T13','now_showing','2026-05-23 11:14:55','2026-06-11 22:37:40',1),(25,'123','1',11,'2026-05-25','12','11','Phiêu lưu','Tiếng Anh','','','T13','now_showing','2026-05-25 11:02:08','2026-06-11 22:37:40',1),(26,'123','ê',133,'2026-05-31','1234','ê','Hành động','Tiếng Anh','','','T13','now_showing','2026-05-31 15:29:05','2026-06-11 22:37:40',1),(27,'ww','eww',-103,'2026-05-31','ư','','Gia đình','Tiếng Anh','e','e','T13','now_showing','2026-05-31 21:00:41','2026-06-11 22:37:40',1),(28,'','db',2,'2026-05-24','d','','Phiêu lưu','Tiếng Anh','','','T13','now_showing','2026-05-31 21:07:14','2026-06-11 22:37:40',1),(29,'','',140,'2026-05-15','Chayanop Boonprakob - Baz Poonpiriya - Atta Hemwadee','','','Tiếng Việt','','','T13','now_showing','2026-06-01 14:38:00','2026-06-11 22:37:40',1),(30,'1','',22,'2026-06-06','2','2','Tình cảm','Tiếng Anh','','','T13','now_showing','2026-06-05 02:01:59','2026-06-11 22:37:40',1);
