/*!50003 DROP PROCEDURE IF EXISTS `AddCinemasRoomsAndSeats` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `AddCinemasRoomsAndSeats`()
BEGIN
    DECLARE done INT DEFAULT FALSE;
    DECLARE current_cinema_id INT;
    DECLARE room_count INT;
    DECLARE rooms_to_add INT;
    DECLARE i INT;
    DECLARE next_room_num INT;
    DECLARE new_room_id INT;
    
    -- Các biến chạy vòng lặp để sinh ghế tự động
    DECLARE row_idx INT;
    DECLARE seat_num INT;
    DECLARE current_row VARCHAR(5);
    DECLARE current_type_id INT;

    -- Con trỏ duyệt qua toàn bộ danh sách rạp phim hiện tại
    DECLARE cinema_cursor CURSOR FOR 
        SELECT id FROM `cinemas`;
        
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    OPEN cinema_cursor;

    read_loop: LOOP
        FETCH cinema_cursor INTO current_cinema_id;
        IF done THEN
            LEAVE read_loop;
        END IF;

        -- Đếm số lượng phòng hiện tại của rạp này
        SELECT COUNT(*) INTO room_count 
        FROM `rooms` 
        WHERE `cinema_id` = current_cinema_id;

        -- Nếu rạp chưa đủ ít nhất 4 phòng chiếu thì tiến hành bù phòng và ghế
        IF room_count < 4 THEN
            SET rooms_to_add = 4 - room_count;
            SET i = 1;

            WHILE i <= rooms_to_add DO
                -- Tính số thứ tự tiếp theo để đặt tên phòng chiếu (Phòng 1, Phòng 2,...)
                SET next_room_num = room_count + i;
                
                -- 1. Thêm bản ghi phòng chiếu mới với tổng số ghế là 90
                INSERT INTO `rooms` (`cinema_id`, `room_name`, `room_type`, `total_seats`, `status`, `is_deleted`)
                VALUES (current_cinema_id, CONCAT('Phòng ', next_room_num), 'Standard', 90, 'active', 0);
                
                -- Lấy ID của phòng chiếu vừa được sinh ra tự động
                SET new_room_id = LAST_INSERT_ID();

                -- 2. Tự động sinh 90 ghế tương ứng chia theo hàng
                SET row_idx = 1;
                row_loop: WHILE row_idx <= 9 DO
                    -- Định nghĩa loại ghế tương ứng với từng hàng từ A -> J (bỏ qua hàng I tránh nhầm lẫn)
                    IF row_idx = 1 THEN SET current_row = 'A'; SET current_type_id = 1;      -- Ghế thường
                    ELSEIF row_idx = 2 THEN SET current_row = 'B'; SET current_type_id = 1; -- Ghế thường
                    ELSEIF row_idx = 3 THEN SET current_row = 'C'; SET current_type_id = 1; -- Ghế thường
                    ELSEIF row_idx = 4 THEN SET current_row = 'D'; SET current_type_id = 1; -- Ghế thường
                    ELSEIF row_idx = 5 THEN SET current_row = 'E'; SET current_type_id = 1; -- Ghế thường
                    ELSEIF row_idx = 6 THEN SET current_row = 'F'; SET current_type_id = 1; -- Ghế thường
                    ELSEIF row_idx = 7 THEN SET current_row = 'G'; SET current_type_id = 2; -- Ghế VIP
                    ELSEIF row_idx = 8 THEN SET current_row = 'H'; SET current_type_id = 2; -- Ghế VIP
                    ELSEIF row_idx = 9 THEN SET current_row = 'J'; SET current_type_id = 3; -- Ghế Đôi (Couple)
                    END IF;

                    -- Vòng lặp thêm số ghế từ 1 đến 10 cho mỗi hàng
                    SET seat_num = 1;
                    WHILE seat_num <= 10 DO
                        INSERT INTO `seats` (`room_id`, `seat_row`, `seat_number`, `seat_type_id`, `status`)
                        VALUES (new_room_id, current_row, seat_num, current_type_id, 'active');
                        SET seat_num = seat_num + 1;
                    END WHILE;

                    SET row_idx = row_idx + 1;
                END WHILE row_loop;

                SET i = i + 1;
            END WHILE;
        END IF;
    END LOOP;

    CLOSE cinema_cursor;
END ;;
DELIMITER ;
